mapper.select:
select er.*,
       e.name as examName,
       s.name as studentName,
       s.student_no as studentNo,
       a.name as approverName
from `exam_record` er
left join `exam` e on er.exam_id = e.id
left join `student` s on er.student_id = s.id
left join `admin` a on er.approved_by = a.id

     and er.exam_id = #{examId}
     and er.student_id = #{studentId}
     and er.status = #{status}
     and er.exam_status = #{examStatus}
     and er.is_published = #{isPublished}

order by er.id desc

mapper.update:
update `exam_record`
set is_published = 0, published_at = null
where exam_id = #{examId}

update `exam_record`
set is_published = 1, published_at = #{publishedAt}
where exam_id = #{examId} and exam_status = 'PASSED'
